// Importamos React y el hook useState desde la librería
import { useState } from 'react';

// Importamos los estilos (el styles.css renombrado a App.css)
import './App.css';


// ══════════════════════════════════════════════
//  DATOS — acá editás el contenido de la carta
// ══════════════════════════════════════════════

const PIZZAS_DESTACADAS = [
  {
    id: 1,
    nombre: "Margherita",
    descripcion: "Tomate San Marzano, mozzarella fior di latte, albahaca fresca y aceite de oliva virgen.",
    precio: "$1.800",
    imagen: "https://images.unsplash.com/photo-1574071318508-1cdbab80d002?w=600&q=80",
    alt: "Pizza Margherita"
  },
  {
    id: 2,
    nombre: "Quattro Formaggi",
    descripcion: "Mozzarella, gorgonzola, parmesano y provolone sobre crema blanca y nuez tostada.",
    precio: "$2.200",
    imagen: "https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=600&q=80",
    alt: "Pizza Quattro Formaggi"
  },
  {
    id: 3,
    nombre: "Diavola",
    descripcion: "Salame picante, tomate, mozzarella, ají rojo y un toque de miel de cayena.",
    precio: "$2.100",
    imagen: "https://images.unsplash.com/photo-1528137871618-79d2761e3fd5?w=600&q=80",
    alt: "Pizza Diavola"
  }
];

const CARTA = {
  pizzas: [
    { id: 1, nombre: "Margherita",          descripcion: "Tomate, mozzarella, albahaca fresca",                     precio: "$1.800" },
    { id: 2, nombre: "Quattro Formaggi",    descripcion: "Mozzarella, gorgonzola, parmesano, provolone",            precio: "$2.200" },
    { id: 3, nombre: "Diavola",             descripcion: "Salame picante, tomate, mozzarella, ají rojo",            precio: "$2.100" },
    { id: 4, nombre: "Prosciutto e Rucola", descripcion: "Jamón crudo, rúcula, mozzarella, parmesano",             precio: "$2.400" },
    { id: 5, nombre: "Funghi Tartufo",      descripcion: "Hongos mixtos, crema de trufa, mozzarella, tomillo",     precio: "$2.600" },
    { id: 6, nombre: "Capricciosa",         descripcion: "Jamón, alcauciles, aceitunas, champiñones, tomate",       precio: "$2.300" },
    { id: 7, nombre: "Napolitana",          descripcion: "Tomate, mozzarella, anchoas, aceitunas negras, orégano", precio: "$1.950" },
    { id: 8, nombre: "Americana",           descripcion: "Panceta, cheddar, cebolla caramelizada, mostaza",         precio: "$2.150" },
  ],
  aperitivos: [
    { id: 1, nombre: "Focaccia al Romero",    descripcion: "Masa de pizza, aceite de oliva, romero y sal gruesa",  precio: "$800"   },
    { id: 2, nombre: "Tabla de Fiambres",     descripcion: "Prosciutto, salame, mortadela, quesos y pan",          precio: "$2.500" },
    { id: 3, nombre: "Arancini",              descripcion: "Croquetas de arroz rellenas de queso y ragú",          precio: "$950"   },
    { id: 4, nombre: "Bruschetta Classica",   descripcion: "Pan tostado, tomate fresco, albahaca y ajo",           precio: "$700"   },
    { id: 5, nombre: "Carpaccio de Zucchini", descripcion: "Calabacín en láminas, limón, parmesano y menta",       precio: "$1.100" },
    { id: 6, nombre: "Calzone Fritto",        descripcion: "Calzone frito relleno de ricota y salame",             precio: "$1.300" },
  ],
  postres: [
    { id: 1, nombre: "Tiramisú della Casa", descripcion: "Receta tradicional con mascarpone y café espresso", precio: "$1.100" },
    { id: 2, nombre: "Panna Cotta",         descripcion: "Con coulis de frutos rojos y menta fresca",         precio: "$950"   },
    { id: 3, nombre: "Pizza Nutella",       descripcion: "Base de pizza dulce, nutella y frutillas frescas",  precio: "$1.200" },
    { id: 4, nombre: "Cannoli Siciliani",   descripcion: "Rellenos de ricota con chips de chocolate",         precio: "$850"   },
  ]
};

const CONTACTO = {
  direccion: "Av. Corrientes 1847, Buenos Aires",
  telefono:  "+54 11 4372-0000",
  whatsapp:  "+54 9 11 5555-1847",
  email:     "reservas@lapiazza.com.ar",
  instagram: "@lapiazza.ba",
  horarios: [
    { dias: "Lunes – Viernes", hora: "19:00 – 00:00" },
    { dias: "Sábados",         hora: "12:00 – 01:00" },
    { dias: "Domingos",        hora: "12:00 – 00:00" },
  ]
};


// ══════════════════════════════════════════════
//  COMPONENTES — los "moldes" reutilizables
// ══════════════════════════════════════════════

// Molde: tarjeta de pizza destacada en el hero
function PizzaCard({ pizza }) {
  return (
    <div className="pizza-card">
      <img src={pizza.imagen} alt={pizza.alt} />
      <div className="card-tag">{pizza.nombre}</div>
      <div className="card-info">
        <h3>{pizza.nombre}</h3>
        <p>{pizza.descripcion}</p>
        <span className="precio">{pizza.precio}</span>
      </div>
    </div>
  );
}

// Molde: fila de ítem en la carta (pizzas / aperitivos / postres)
function MenuItem({ item }) {
  return (
    <div className="menu-item">
      <div className="menu-item-info">
        <h4>{item.nombre}</h4>
        <p>{item.descripcion}</p>
      </div>
      <span className="menu-item-precio">{item.precio}</span>
    </div>
  );
}

// Molde: fila de horario en contacto
function HoraFila({ fila }) {
  return (
    <div className="hora-fila">
      <span>{fila.dias}</span>
      <span>{fila.hora}</span>
    </div>
  );
}

// Molde: dato de contacto (ícono + etiqueta + valor)
function DatoContacto({ icono, etiqueta, valor }) {
  return (
    <div className="dato">
      <div className="dato-icono">{icono}</div>
      <div className="dato-texto">
        <strong>{etiqueta}</strong>
        <span>{valor}</span>
      </div>
    </div>
  );
}


// ══════════════════════════════════════════════
//  SECCIONES
// ══════════════════════════════════════════════

function Nav() {
  return (
    <nav>
      <div className="logo">La Piazza</div>
      <ul>
        <li><a href="#inicio">Inicio</a></li>
        <li><a href="#carta">Carta</a></li>
        <li><a href="#contacto">Contacto</a></li>
      </ul>
    </nav>
  );
}

function Hero() {
  return (
    <section id="inicio">
      <p className="hero-label">Pizzería Artesanal · Desde 1994</p>
      <h1 className="hero-title">La <span>Piazza</span></h1>
      <p className="hero-sub">Masa madre, ingredientes frescos y el horno de leña que lleva generaciones encendido.</p>

      <div className="pizza-grid">
        {PIZZAS_DESTACADAS.map(pizza => (
          <PizzaCard key={pizza.id} pizza={pizza} />
        ))}
      </div>

      <div className="cta-wrap">
        <a href="#carta" className="btn-carta">Ver carta completa</a>
      </div>
    </section>
  );
}

function Carta() {
  // useState: guarda qué tab está activa. Valor inicial: "pizzas"
  const [tabActiva, setTabActiva] = useState("pizzas");

  const tabs = [
    { key: "pizzas",     label: "Pizzas"     },
    { key: "aperitivos", label: "Aperitivos" },
    { key: "postres",    label: "Postres"    },
  ];

  return (
    <>
      <div className="divisor"><span></span><em>· Nuestra Carta ·</em><span></span></div>

      <section id="carta">
        <h2 className="seccion-titulo">Lo que sale del horno</h2>
        <p className="seccion-sub">Pizzas · Aperitivos · Postres</p>

        {/* Tabs: al hacer click se actualiza tabActiva con setTabActiva */}
        <div className="tabs">
          {tabs.map(tab => (
            <button
              key={tab.key}
              className={`tab-btn ${tabActiva === tab.key ? "activo" : ""}`}
              onClick={() => setTabActiva(tab.key)}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Muestra los ítems de la tab activa usando el molde MenuItem */}
        <div className="menu-grid">
          {CARTA[tabActiva].map(item => (
            <MenuItem key={item.id} item={item} />
          ))}
        </div>
      </section>
    </>
  );
}

function Contacto() {
  return (
    <>
      <div className="divisor"><span></span><em>· Encontranos ·</em><span></span></div>

      <section id="contacto">
        <div className="contacto-inner">

          <div className="contacto-texto">
            <h2>Reservá tu mesa</h2>
            <p>Estamos en el corazón del barrio, esperándote con el horno encendido y una buena botella de vino. Hacé tu reserva por teléfono o WhatsApp.</p>

            <div className="horarios">
              <h3>Horarios de atención</h3>
              {CONTACTO.horarios.map((fila, i) => (
                <HoraFila key={i} fila={fila} />
              ))}
            </div>
          </div>

          <div className="contacto-datos">
            <DatoContacto icono="📍" etiqueta="Dirección"  valor={CONTACTO.direccion}  />
            <DatoContacto icono="📞" etiqueta="Teléfono"   valor={CONTACTO.telefono}   />
            <DatoContacto icono="💬" etiqueta="WhatsApp"   valor={CONTACTO.whatsapp}   />
            <DatoContacto icono="✉️" etiqueta="Email"      valor={CONTACTO.email}      />
            <DatoContacto icono="📷" etiqueta="Instagram"  valor={CONTACTO.instagram}  />
          </div>

        </div>
      </section>
    </>
  );
}

function Footer() {
  return (
    <footer>
      © 2025 <em>La Piazza</em> · Todos los derechos reservados · Hecho con 🍕 en Buenos Aires
    </footer>
  );
}


// ══════════════════════════════════════════════
//  APP RAÍZ — ensambla todas las secciones
//  Este es el componente que exportamos para
//  que src/index.js lo pueda importar y montar
// ══════════════════════════════════════════════

export default function App() {
  return (
    <>
      <Nav />
      <Hero />
      <Carta />
      <Contacto />
      <Footer />
    </>
  );
}
